import React from 'react';
import {Button} from '@gravity-ui/uikit';
import {ConfirmDialog} from '@gravity-ui/components';

export function DeleteConfirmation({onDelete}) {
  const [open, setOpen] = React.useState(false);
  const [loading, setLoading] = React.useState(false);

  const handleConfirm = async () => {
    setLoading(true);
    try {
      await onDelete();
      setOpen(false);
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <Button view="outlined-danger" onClick={() => setOpen(true)}>
        Delete
      </Button>
      <ConfirmDialog
        open={open}
        onClose={() => setOpen(false)}
        title="Delete this item?"
        message="This action cannot be undone. The item and all associated data will be permanently removed."
        textButtonApply="Delete"
        textButtonCancel="Cancel"
        propsButtonApply={{view: 'outlined-danger', loading}}
        propsButtonCancel={{disabled: loading}}
        onClickButtonApply={handleConfirm}
        onClickButtonCancel={() => setOpen(false)}
      />
    </>
  );
}

import React from 'react';
import {Dialog, Button, Checkbox} from '@gravity-ui/uikit';

export function PublishConfirmation({onPublish}) {
  const [open, setOpen] = React.useState(false);
  const [notifySubscribers, setNotifySubscribers] = React.useState(true);

  return (
    <>
      <Button view="action" onClick={() => setOpen(true)}>
        Publish
      </Button>
      <Dialog open={open} onClose={() => setOpen(false)} size="s">
        <Dialog.Header caption="Publish changes?" />
        <Dialog.Body>
          Publishing will make your draft visible to all users.
          <Checkbox
            checked={notifySubscribers}
            onUpdate={setNotifySubscribers}
            style={{marginTop: 12}}
          >
            Notify subscribers
          </Checkbox>
        </Dialog.Body>
        <Dialog.Footer
          textButtonApply="Publish"
          textButtonCancel="Cancel"
          propsButtonApply={{view: 'action'}}
          onClickButtonApply={() => {
            onPublish({notifySubscribers});
            setOpen(false);
          }}
          onClickButtonCancel={() => setOpen(false)}
        />
      </Dialog>
    </>
  );
}

import React from 'react';
import {Table, Pagination, DropdownMenu, ActionsPanel, Label, Checkbox, Select, TextInput, Icon} from '@gravity-ui/uikit';
import {Magnifier} from '@gravity-ui/icons';

const STATUS_OPTIONS = [
  {value: 'all', content: 'All statuses'},
  {value: 'active', content: 'Active'},
  {value: 'inactive', content: 'Inactive'},
  {value: 'pending', content: 'Pending'},
];

const STATUS_THEME = {
  active: 'success',
  inactive: 'normal',
  pending: 'warning',
};

export function DataTableWithFilters({data, onEdit, onDelete, onExport}) {
  const [filter, setFilter] = React.useState('');
  const [statusFilter, setStatusFilter] = React.useState(['all']);
  const [page, setPage] = React.useState(1);
  const [pageSize, setPageSize] = React.useState(20);
  const [selectedIds, setSelectedIds] = React.useState(new Set());
  const [sortColumn, setSortColumn] = React.useState(null);
  const [sortOrder, setSortOrder] = React.useState('asc');

  // 1. Filter
  const filteredData = React.useMemo(() => {
    let result = data;
    if (filter) {
      const lc = filter.toLowerCase();
      result = result.filter((row) =>
        row.name.toLowerCase().includes(lc) ||
        row.email.toLowerCase().includes(lc)
      );
    }
    if (statusFilter[0] !== 'all') {
      result = result.filter((row) => row.status === statusFilter[0]);
    }
    return result;
  }, [data, filter, statusFilter]);

  // 2. Sort
  const sortedData = React.useMemo(() => {
    if (!sortColumn) return filteredData;
    return [...filteredData].sort((a, b) => {
      const valA = a[sortColumn] ?? '';
      const valB = b[sortColumn] ?? '';
      const cmp = String(valA).localeCompare(String(valB));
      return sortOrder === 'asc' ? cmp : -cmp;
    });
  }, [filteredData, sortColumn, sortOrder]);

  // 3. Paginate
  const paginatedRows = React.useMemo(() => {
    const start = (page - 1) * pageSize;
    return sortedData.slice(start, start + pageSize);
  }, [sortedData, page, pageSize]);

  const pageIds = new Set(paginatedRows.map((row) => row.id));
  const allPageSelected = paginatedRows.length > 0 && paginatedRows.every((row) => selectedIds.has(row.id));

  const toggleRow = (id) => {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const toggleAll = () => {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      if (allPageSelected) {
        pageIds.forEach((id) => next.delete(id));
      } else {
        pageIds.forEach((id) => next.add(id));
      }
      return next;
    });
  };

  const clearSelection = () => setSelectedIds(new Set());

  const handlePageUpdate = (nextPage, nextPageSize) => {
    if (nextPageSize !== pageSize) {
      setPageSize(nextPageSize);
      setPage(1);
    } else {
      setPage(nextPage);
    }
  };

  const columns = [
    {
      id: '_selection',
      name: () => (
        <Checkbox
          checked={allPageSelected}
          indeterminate={!allPageSelected && paginatedRows.some((r) => selectedIds.has(r.id))}
          onUpdate={toggleAll}
        />
      ),
      template: (row) => (
        <Checkbox
          checked={selectedIds.has(row.id)}
          onUpdate={() => toggleRow(row.id)}
        />
      ),
      width: 40,
      sticky: 'start',
    },
    {id: 'name', name: 'Name'},
    {id: 'email', name: 'Email'},
    {
      id: 'status',
      name: 'Status',
      template: (row) => (
        <Label theme={STATUS_THEME[row.status] || 'normal'}>
          {row.status.charAt(0).toUpperCase() + row.status.slice(1)}
        </Label>
      ),
    },
    {id: 'createdAt', name: 'Created'},
    {
      id: '_actions',
      name: '',
      template: (row) => (
        <DropdownMenu
          items={[
            {text: 'Edit', action: () => onEdit(row)},
            {text: 'Duplicate', action: () => onEdit({...row, id: undefined})},
            {text: 'Delete', action: () => onDelete([row.id]), theme: 'danger'},
          ]}
          size="s"
        />
      ),
      width: 60,
      sticky: 'end',
    },
  ];

  return (
    <div>
      <div style={{display: 'flex', gap: 12, alignItems: 'center', marginBottom: 16}}>
        <TextInput
          value={filter}
          onUpdate={setFilter}
          placeholder="Search by name or email..."
          hasClear
          leftContent={<Icon data={Magnifier} size={16} />}
          style={{maxWidth: 360}}
        />
        <Select
          value={statusFilter}
          onUpdate={setStatusFilter}
          options={STATUS_OPTIONS}
          placeholder="All statuses"
          width={180}
        />
      </div>

      <Table
        data={paginatedRows}
        columns={columns}
        getRowId={(row) => row.id}
        emptyMessage="No results match your filters"
        edgePadding
        stickyHorizontalScroll
      />

      <div style={{marginTop: 16}}>
        <Pagination
          page={page}
          pageSize={pageSize}
          total={filteredData.length}
          pageSizeOptions={[10, 20, 50, 100]}
          onUpdate={handlePageUpdate}
        />
      </div>

      {selectedIds.size > 0 && (
        <ActionsPanel
          actions={[
            {id: 'delete', text: 'Delete selected', handler: () => onDelete([...selectedIds]), theme: 'danger'},
            {id: 'export', text: 'Export selected', handler: () => onExport([...selectedIds])},
          ]}
          onClose={clearSelection}
          renderNote={() => `${selectedIds.size} item${selectedIds.size > 1 ? 's' : ''} selected`}
        />
      )}
    </div>
  );
}

import React from 'react';
import {FilePreview, Progress, Button, Icon, Text, Card, Alert} from '@gravity-ui/uikit';
import {ArrowUpFromLine, TrashBin, Xmark, ArrowRotateLeft} from '@gravity-ui/icons';

const MAX_FILE_SIZE = 10 * 1024 * 1024; // 10 MB
const ALLOWED_TYPES = ['image/png', 'image/jpeg', 'application/pdf'];

function validateFile(file) {
  if (!ALLOWED_TYPES.includes(file.type)) {
    return `Unsupported file type: ${file.type}`;
  }
  if (file.size > MAX_FILE_SIZE) {
    return `File too large: ${(file.size / 1024 / 1024).toFixed(1)} MB (max 10 MB)`;
  }
  return null;
}

function uploadFile(file, onProgress) {
  const controller = new AbortController();
  const promise = new Promise((resolve, reject) => {
    const xhr = new XMLHttpRequest();
    xhr.open('POST', '/api/upload');

    controller.signal.addEventListener('abort', () => xhr.abort());

    xhr.upload.addEventListener('progress', (e) => {
      if (e.lengthComputable) {
        onProgress(Math.round((e.loaded / e.total) * 100));
      }
    });

    xhr.addEventListener('load', () => {
      if (xhr.status >= 200 && xhr.status < 300) {
        resolve(JSON.parse(xhr.responseText));
      } else {
        reject(new Error(`Upload failed: ${xhr.status}`));
      }
    });

    xhr.addEventListener('error', () => reject(new Error('Network error')));
    xhr.addEventListener('abort', () => reject(new Error('Upload cancelled')));

    const formData = new FormData();
    formData.append('file', file);
    xhr.send(formData);
  });

  return {promise, controller};
}

export function FileUploadWithPreview({onUploadComplete, maxFiles = 5}) {
  const [entries, setEntries] = React.useState([]);
  const [errors, setErrors] = React.useState([]);
  const [dragOver, setDragOver] = React.useState(false);
  const inputRef = React.useRef(null);
  const controllersRef = React.useRef({});

  const handleFiles = React.useCallback((fileList) => {
    const files = Array.from(fileList);
    const newErrors = [];
    const newEntries = [];

    files.forEach((file) => {
      const error = validateFile(file);
      if (error) {
        newErrors.push(error);
        return;
      }
      const id = `${file.name}-${Date.now()}-${Math.random()}`;
      const imageSrc = file.type.startsWith('image/') ? URL.createObjectURL(file) : undefined;
      newEntries.push({id, file, imageSrc, status: 'pending', progress: 0, error: null});
    });

    setErrors(newErrors);
    setEntries((prev) => {
      const combined = [...prev, ...newEntries].slice(0, maxFiles);
      return combined;
    });

    // Start uploads
    newEntries.forEach((entry) => startUpload(entry.id, entry.file));
  }, [maxFiles]);

  const startUpload = (id, file) => {
    setEntries((prev) =>
      prev.map((e) => (e.id === id ? {...e, status: 'uploading', progress: 0, error: null} : e)),
    );

    const {promise, controller} = uploadFile(file, (progress) => {
      setEntries((prev) => prev.map((e) => (e.id === id ? {...e, progress} : e)));
    });

    controllersRef.current[id] = controller;

    promise
      .then(() => {
        setEntries((prev) => prev.map((e) => (e.id === id ? {...e, status: 'done', progress: 100} : e)));
      })
      .catch((err) => {
        if (err.message !== 'Upload cancelled') {
          setEntries((prev) =>
            prev.map((e) => (e.id === id ? {...e, status: 'error', error: err.message} : e)),
          );
        }
      })
      .finally(() => {
        delete controllersRef.current[id];
      });
  };

  const removeEntry = (id) => {
    controllersRef.current[id]?.abort();
    setEntries((prev) => {
      const entry = prev.find((e) => e.id === id);
      if (entry?.imageSrc) URL.revokeObjectURL(entry.imageSrc);
      return prev.filter((e) => e.id !== id);
    });
  };

  const retryEntry = (id) => {
    const entry = entries.find((e) => e.id === id);
    if (entry) startUpload(id, entry.file);
  };

  const handleDrop = (e) => {
    e.preventDefault();
    setDragOver(false);
    if (e.dataTransfer.files.length) handleFiles(e.dataTransfer.files);
  };

  const progressTheme = (status) => {
    if (status === 'done') return 'success';
    if (status === 'error') return 'danger';
    return 'default';
  };

  return (
    <div>
      <Card
        view="outlined"
        style={{
          border: dragOver ? '2px dashed var(--g-color-line-brand)' : '2px dashed var(--g-color-line-generic)',
          padding: 32,
          textAlign: 'center',
          cursor: 'pointer',
          transition: 'border-color 0.15s',
          background: dragOver ? 'var(--g-color-base-brand-hover)' : undefined,
        }}
        onDragEnter={(e) => { e.preventDefault(); setDragOver(true); }}
        onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
        onDragLeave={() => setDragOver(false)}
        onDrop={handleDrop}
        onClick={() => inputRef.current?.click()}
      >
        <Icon data={ArrowUpFromLine} size={32} />
        <div style={{marginTop: 8}}>
          <Text variant="body-2">Drag files here or</Text>
        </div>
        <Button view="outlined" size="m" style={{marginTop: 8}} onClick={(e) => { e.stopPropagation(); inputRef.current?.click(); }}>
          Browse files
        </Button>
        <input
          ref={inputRef}
          type="file"
          multiple
          accept={ALLOWED_TYPES.join(',')}
          style={{display: 'none'}}
          onChange={(e) => { if (e.target.files.length) handleFiles(e.target.files); e.target.value = ''; }}
        />
        <div style={{marginTop: 8}}>
          <Text variant="caption-1" color="secondary">PNG, JPEG, PDF up to 10 MB</Text>
        </div>
      </Card>

      {errors.length > 0 && (
        <div style={{marginTop: 12}}>
          {errors.map((err, i) => (
            <Alert key={i} theme="danger" message={err} onClose={() => setErrors((prev) => prev.filter((_, j) => j !== i))} style={{marginBottom: 4}} />
          ))}
        </div>
      )}

      {entries.length > 0 && (
        <div style={{marginTop: 16, display: 'flex', flexWrap: 'wrap', gap: 12}}>
          {entries.map((entry) => (
            <div key={entry.id} style={{width: 120}}>
              <FilePreview
                file={entry.file}
                imageSrc={entry.imageSrc}
                actions={[
                  {
                    icon: <Icon data={entry.status === 'uploading' ? Xmark : TrashBin} size={14} />,
                    title: entry.status === 'uploading' ? 'Cancel' : 'Remove',
                    onClick: () => removeEntry(entry.id),
                  },
                  ...(entry.status === 'error'
                    ? [{
                        icon: <Icon data={ArrowRotateLeft} size={14} />,
                        title: 'Retry',
                        onClick: () => retryEntry(entry.id),
                      }]
                    : []),
                ]}
              />
              {entry.status !== 'done' && (
                <Progress
                  value={entry.progress}
                  theme={progressTheme(entry.status)}
                  size="s"
                />
              )}
              {entry.status === 'done' && (
                <Progress value={100} theme="success" size="s" />
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import React from 'react';
import {FilePreview, Progress, Button, Icon, Text} from '@gravity-ui/uikit';
import {ArrowUpFromLine, TrashBin} from '@gravity-ui/icons';

export function SingleFileUpload({onFileReady}) {
  const [file, setFile] = React.useState(null);
  const [progress, setProgress] = React.useState(0);
  const [uploading, setUploading] = React.useState(false);
  const inputRef = React.useRef(null);

  const handleSelect = (e) => {
    const selected = e.target.files[0];
    if (!selected) return;
    setFile(selected);
    setProgress(0);
    onFileReady?.(selected);
    e.target.value = '';
  };

  const handleRemove = () => {
    setFile(null);
    setProgress(0);
    setUploading(false);
  };

  return (
    <div>
      {!file ? (
        <div>
          <Button view="outlined" onClick={() => inputRef.current?.click()}>
            <Icon data={ArrowUpFromLine} size={16} />
            Choose file
          </Button>
          <input
            ref={inputRef}
            type="file"
            style={{display: 'none'}}
            onChange={handleSelect}
          />
        </div>
      ) : (
        <div style={{width: 120}}>
          <FilePreview
            file={file}
            view="compact"
            imageSrc={file.type.startsWith('image/') ? URL.createObjectURL(file) : undefined}
            actions={[{
              icon: <Icon data={TrashBin} size={14} />,
              title: 'Remove',
              onClick: handleRemove,
            }]}
          />
          {uploading && (
            <Progress value={progress} size="s" text={`${progress}%`} />
          )}
        </div>
      )}
    </div>
  );
}

import React from 'react';
import {Skeleton, Loader, PlaceholderContainer} from '@gravity-ui/uikit';

function PageSkeleton() {
  return (
    <div style={{display: 'flex', flexDirection: 'column', gap: 16}}>
      <Skeleton style={{height: 32, width: '60%'}} />
      <Skeleton style={{height: 20, width: '100%'}} />
      <Skeleton style={{height: 20, width: '100%'}} />
      <Skeleton style={{height: 20, width: '80%'}} />
    </div>
  );
}

export function PageContent({data, isLoading, error, refetch}) {
  if (error) {
    return (
      <PlaceholderContainer
        title="Something went wrong"
        description={error.message || 'An unexpected error occurred. Please try again.'}
        image={<img src="/images/error.svg" alt="Error" width={230} />}
        size="l"
        direction="column"
        align="center"
        actions={[{text: 'Retry', view: 'action', onClick: refetch}]}
      />
    );
  }

  if (isLoading) {
    return <PageSkeleton />;
  }

  if (!data || data.length === 0) {
    return (
      <PlaceholderContainer
        title="No results found"
        description="Try adjusting your search or filters to find what you are looking for."
        image={<img src="/images/empty.svg" alt="No results" width={230} />}
        size="l"
        direction="column"
        align="center"
      />
    );
  }

  return (
    <div>
      {data.map((item) => (
        <div key={item.id}>{item.name}</div>
      ))}
    </div>
  );
}

import React from 'react';
import {Loader, PlaceholderContainer} from '@gravity-ui/uikit';

export function SectionContent({data, isLoading, error, refetch}) {
  if (error) {
    return (
      <PlaceholderContainer
        title="Failed to load section"
        description={error.message}
        image={<img src="/images/error.svg" alt="Error" width={150} />}
        size="m"
        actions={[{text: 'Retry', view: 'outlined', onClick: refetch}]}
      />
    );
  }

  if (isLoading) {
    return (
      <div style={{display: 'flex', justifyContent: 'center', padding: 40}}>
        <Loader size="l" />
      </div>
    );
  }

  if (!data || data.length === 0) {
    return (
      <PlaceholderContainer
        title="Nothing here yet"
        description="This section is empty."
        image={<img src="/images/empty.svg" alt="Empty" width={150} />}
        size="s"
      />
    );
  }

  return <div>{data.map((item) => <div key={item.id}>{item.name}</div>)}</div>;
}

