import React from 'react';
import '@gravity-ui/uikit/styles/fonts.css';
import '@gravity-ui/uikit/styles/styles.css';
import {ThemeProvider, useTheme, RadioGroup, Text, Flex} from '@gravity-ui/uikit';

const themeOptions = [
  {value: 'light', content: 'Light'},
  {value: 'dark', content: 'Dark'},
  {value: 'system', content: 'System'},
];

function ThemeSelector() {
  const [theme, setTheme] = useTheme();

  return (
    <Flex alignItems="center" gap={3}>
      <Text variant="body-1">Theme:</Text>
      <RadioGroup
        options={themeOptions}
        value={theme}
        onUpdate={setTheme}
      />
    </Flex>
  );
}

function App() {
  return (
    <Flex direction="column" gap={4} style={{padding: 20}}>
      <ThemeSelector />
      <Text variant="body-1">
        All Gravity UI components inside ThemeProvider automatically
        respond to theme changes via CSS custom properties.
      </Text>
    </Flex>
  );
}

export default function Root() {
  return (
    <ThemeProvider theme="system">
      <App />
    </ThemeProvider>
  );
}

